def can_capture(self, board, start, end):
    x_start, y_start = start
    x_end, y_end = end
    dx, dy = (x_end - x_start), (y_end - y_start)

    if abs(dx) != 2 or abs(dy) != 2:
        return False

    capture_piece_x, capture_piece_y = (x_start + dx // 2), (y_start + dy // 2)
    if board.get_piece(capture_piece_x, capture_piece_y).color == self.color:
        return False

    return True
```

